<?php require_once 'includes/auth.php'; require_login(); $user=current_user(); if(isset($_GET['token'])){ $token=$_GET['token']; $stmt=$pdo->prepare('SELECT * FROM events WHERE token=?'); $stmt->execute([$token]); $event=$stmt->fetch(); if(!$event){ $_SESSION['flash']='Invalid token'; header('Location: index.php'); exit; } try{ $stmt=$pdo->prepare('INSERT INTO attendance (event_id,user_id) VALUES (?,?)'); $stmt->execute([$event['id'],$user['id']]); $pdo->prepare('UPDATE users SET points = points + 10 WHERE id = ?')->execute([$user['id']]); $_SESSION['flash']='Attendance recorded via QR'; }catch(Exception $e){ $_SESSION['flash']='Attendance already recorded'; } header('Location: view_event.php?id='.$event['id']); exit; } elseif($_SERVER['REQUEST_METHOD']==='POST'){ $event_id=intval($_POST['event_id']); try{ $stmt=$pdo->prepare('INSERT INTO attendance (event_id,user_id) VALUES (?,?)'); $stmt->execute([$event_id,$user['id']]); $pdo->prepare('UPDATE users SET points = points + 10 WHERE id = ?')->execute([$user['id']]); $_SESSION['flash']='Attendance marked'; }catch(Exception $e){ $_SESSION['flash']='Already marked'; } header('Location: view_event.php?id='.$event_id); exit; } else{ header('Location: index.php'); exit; } ?>